def cached_response(cache: DiskCache, ttl: Optional[int] = None, key_prefix: str = ""):
    """Decorator to cache Flask route responses."""

    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            cache_key = _build_cache_key(key_prefix, f.__name__, request)

            cached_data = cache.get(cache_key)
            if cached_data is not None:
                if isinstance(cached_data, dict):
                    cached_data["_cache"] = "hit"
                return jsonify(cached_data)

            result = f(*args, **kwargs)

            if isinstance(result, dict):
                cache.set(cache_key, result, ttl=ttl)
                result["_cache"] = "miss"
                return jsonify(result)

            return result

        return wrapper

    return decorator


def _build_cache_key(prefix: str, func_name: str, req) -> str:
    parts = [prefix, func_name, req.path]
    sorted_args = sorted(req.args.items())
    for k, v in sorted_args:
        parts.append(f"{k}={v}")
    return "|".join(parts)


